var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......방문할 때마다 내사과 기질을 억눌러 왔지만, 오늘만은 꼭 말씀 드려야겠습니다.","JPN":"……ここに訪れるたびに内偵課としての気質を抑えるのに苦労しましたが、今日という今日は言わせてもらいます。","ENG":"Every time I visited your office, I tried hard not to point things out. But today I have to.","TWN":"……雖然每次到這裡，我都在克制我火爆的脾氣，但今天一定要告訴您。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"종신계약이 태스크포스 업계에서 의미 있는 자리임은 숙지하고 있습니다.","JPN":"タスクフォースカンパニー業界において、終身契約に大きな意味があることは知っています。","ENG":"I understand the significance of the lifetime contract in the TASKFORCE industry.","TWN":"我深知「終身契約」在特遣勢力業界中的意義。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만 이런 과도한 인테리어는 회사의 운용 자산을 불필요하게 소모하고, 재정 상태 악화와 직원들의 모티베이션 저하에......","JPN":"しかし、このような過剰な装飾は、会社の運用資産を無意味に消費させ、財政の悪化と社員のモチベーション低下を招き……","ENG":"But you shouldn't have wasted the company's budget on such excessive decorations, not to mention their demoralizing effect—","TWN":"但是，這種過度裝飾會無端消耗公司的資產，導致財務惡化和員工的幹勁低下……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"방금 뭐라고 하셨습니까? 저를 위해서?","JPN":"今、何と言いましたか？　僕のために？","ENG":"Excuse me? You've done this for me?","TWN":"您剛才說什麼？這是為我做的？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......사장님, 전 사장님을 수행할 기회를 얻어서 다행이라고 생각합니다.","JPN":"……社長、\\n僕は社長に随行する機会を得られてよかったと思っています。","ENG":"Boss, I feel lucky that I get to assist you from your side.","TWN":"……老闆，能獲得跟隨您的機會，我感到非常榮幸。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그리고 그건 사장님의 리더쉽과 선을 넘지 않는 직업관 때문이지, 저를 특별히 대우해 주시는 것 때문이 아닙니다.","JPN":"それは社長のリーダーシップと、線引きがはっきりしている職業観に敬意を抱いているからであって、特別待遇を求めてのことではありません。","ENG":"And that's not because of your special treatment of me, but because of your leadership and business ethics.","TWN":"而且，這是因為老闆的領導能力和不逾矩的職業觀，並不是因為您對我有特別待遇。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"굳이 이런 거창한 자리가 아니라도, 사장님께서 직원들을 얼마나 아끼는지는 저뿐만 아니라 모두들 알고 있을 겁니다.","JPN":"このような大げさな席を設けずとも、社長が社員たちを大事に思ってくださっていることは、僕のみならず全社員にとって周知の事実でしょう。","ENG":"Even if you don't do all this, everyone at the company knows how much you care about them.","TWN":"您不必刻意幫我安排這麼高的職位。老闆有多麼珍惜員工，不只是我，大家都知道。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"인테리어에 대해서는 특별히 이번 한 번만 넘어가 드리겠습니다.","JPN":"装飾に関しましては、今回のみ特別に見逃してあげます。","ENG":"I'll let it slide this time.","TWN":"至於室內裝飾，這次我就特別放過您吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그러니까, 부탁드립니다. 앞으로 이런 과도한 인테리어는 되도록 참아 주십시오.","JPN":"ですから、どうかお願いします。今後、このような過剰な装飾はなるべく控えてください。","ENG":"But please try not to get carried away with decorations like this.","TWN":"所以拜託您，今後請盡量減少這種過度的室內裝飾。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......하지만 저 때문에 이런 성의를 보여주신다는 건, 어쩔 수 없이 기쁘군요.","JPN":"……しかしながら、僕のためにここまでしていただけて、やはり嬉しく感じてしまうのも事実です。","ENG":"But I must say that I'm infinitely grateful for the thought behind them.","TWN":"……但是為了我，您會願意展現這樣的誠意，我還是不由得地感到高興。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};